  min := inputs[0];
  var idx := 1;
  while idx < inputs.Length
    invariant 1 <= idx <= inputs.Length
    invariant forall i :: 0 <= i < idx ==> min <= inputs[i]
    invariant exists i :: 0 <= i < idx && min == inputs[i]
